class Solution {
public:
    int brokenCalc(int startValue, int target) {
        long long start = startValue, tar = target;
        int res = 0;
        while (tar > start) {
            if (tar % 2 == 1) tar++;
            else tar /= 2;
            res++;
        }
        return res + start - tar;
    }
};
